import os
import time
import re
from collections import defaultdict

class LateralMovementDetector:
    """Lateral movement detector from Windows event logs"""

    LATERAL_TECHNIQUES = {
        'PsExec': {'events': [7045, 4624], 'indicators': ['PSEXESVC', 'Type 3 logon']},
        'WMI': {'events': [4624, 4648], 'indicators': ['WMI provider host', 'wmic.exe']},
        'WinRM': {'events': [4624, 91], 'indicators': ['Type 3 logon', 'WSMan']},
        'RDP': {'events': [4624, 1149], 'indicators': ['Type 10 logon']},
        'SMB': {'events': [4624, 5140], 'indicators': ['Type 3 logon', 'IPC$', 'ADMIN$']},
        'DCOM': {'events': [4624, 4688], 'indicators': ['mmc.exe', 'ShellWindows']},
        'SSH': {'events': [4624], 'indicators': ['OpenSSH', 'Type 3']},
        'ScheduledTask': {'events': [4698, 4702], 'indicators': ['at.exe', 'schtasks']},
    }

    DETECTION_RULES = {
        'new_admin_logon': 'Type 3/10 logon with admin privileges from new source',
        'service_install': 'New service created on remote host',
        'admin_share_access': 'Access to ADMIN$ or C$ share',
        'rapid_host_hopping': 'Same user authenticating to 3+ hosts in 10 minutes',
        'pass_the_hash': 'NTLM logon without prior interactive session',
        'golden_ticket': 'TGS request for non-existent user or very old TGT',
    }

    def __init__(self):
        self.logon_events = []
        self.alerts = []

    def add_logon(self, timestamp, user, source_ip, dest_host, logon_type, privileges=False):
        self.logon_events.append({
            'time': timestamp, 'user': user, 'source': source_ip,
            'dest': dest_host, 'type': logon_type, 'admin': privileges,
        })

    def detect_host_hopping(self, window=600):
        user_hosts = defaultdict(lambda: defaultdict(set))

        for event in self.logon_events:
            if event['type'] in (3, 10):
                time_bucket = event['time'] // window
                user_hosts[event['user']][time_bucket].add(event['dest'])

        alerts = []
        for user, buckets in user_hosts.items():
            for bucket, hosts in buckets.items():
                if len(hosts) >= 3:
                    alerts.append({
                        'type': 'HOST_HOPPING',
                        'severity': 'HIGH',
                        'user': user,
                        'hosts': list(hosts),
                        'count': len(hosts),
                        'mitre': 'T1021',
                    })
        return alerts

    def detect_pass_the_hash(self):
        user_interactive = set()
        alerts = []

        for event in sorted(self.logon_events, key=lambda e: e['time']):
            if event['type'] in (2, 10, 11):  # Interactive logon types
                user_interactive.add(event['user'])
            elif event['type'] == 3 and event['admin']:
                if event['user'] not in user_interactive:
                    alerts.append({
                        'type': 'PASS_THE_HASH',
                        'severity': 'CRITICAL',
                        'user': event['user'],
                        'source': event['source'],
                        'dest': event['dest'],
                        'mitre': 'T1550.002',
                    })
        return alerts

    def run(self):
        print('=== Lateral Movement Detector ===')
        detector = LateralMovementDetector()

        print('[*] Lateral movement techniques:')
        for tech, info in detector.LATERAL_TECHNIQUES.items():
            print(f'    {tech}: Events {info["events"]}, Indicators: {", ".join(info["indicators"])}')

        base = int(time.time())
        detector.add_logon(base, 'attacker', '10.0.0.50', 'DC01', 3, True)
        detector.add_logon(base + 60, 'attacker', '10.0.0.50', 'FILE01', 3, True)
        detector.add_logon(base + 120, 'attacker', '10.0.0.50', 'WEB01', 3, True)
        detector.add_logon(base + 180, 'attacker', '10.0.0.50', 'DB01', 3, True)

        print(f'\n--- Host Hopping Detection ---')
        hop_alerts = detector.detect_host_hopping()
        for a in hop_alerts:
            print(f'    [{a["severity"]}] {a["user"]} → {len(a["hosts"])} hosts: {", ".join(a["hosts"])}')

        print(f'\n--- Pass-the-Hash Detection ---')
        pth_alerts = detector.detect_pass_the_hash()
        for a in pth_alerts:
            print(f'    [{a["severity"]}] {a["user"]}: {a["source"]} → {a["dest"]} (no prior interactive logon)')

        print(f'\n[*] Detection rules:')
        for name, desc in detector.DETECTION_RULES.items():
            print(f'    {name}: {desc}')

        print(f'\n[*] Key events: 4624 (logon), 4648 (explicit creds), 5140 (share access)')

detector = LateralMovementDetector()
detector.run()

