import os
import time
from collections import defaultdict

class ProcessTreeAnalyzer:
    """Process tree analyzer for injection detection"""

    SUSPICIOUS_PARENT_CHILD = {
        'Office spawning shell': {
            'parents': ['winword.exe', 'excel.exe', 'powerpnt.exe', 'outlook.exe'],
            'children': ['cmd.exe', 'powershell.exe', 'wscript.exe', 'cscript.exe', 'mshta.exe', 'certutil.exe'],
            'severity': 'CRITICAL', 'mitre': 'T1204.002',
        },
        'Browser spawning cmd': {
            'parents': ['chrome.exe', 'firefox.exe', 'msedge.exe', 'iexplore.exe'],
            'children': ['cmd.exe', 'powershell.exe'],
            'severity': 'HIGH', 'mitre': 'T1189',
        },
        'Service spawning shell': {
            'parents': ['svchost.exe', 'services.exe', 'spoolsv.exe'],
            'children': ['cmd.exe', 'powershell.exe', 'net.exe', 'net1.exe'],
            'severity': 'HIGH', 'mitre': 'T1543',
        },
        'WMI execution': {
            'parents': ['wmiprvse.exe'],
            'children': ['cmd.exe', 'powershell.exe'],
            'severity': 'HIGH', 'mitre': 'T1047',
        },
        'Task Scheduler execution': {
            'parents': ['taskeng.exe', 'taskhostw.exe'],
            'children': ['cmd.exe', 'powershell.exe'],
            'severity': 'MEDIUM', 'mitre': 'T1053',
        },
    }

    INJECTION_INDICATORS = {
        'Remote thread': 'CreateRemoteThread into another process',
        'APC injection': 'QueueUserAPC to inject code',
        'Process hollowing': 'Suspend → Unmap → Write → Resume',
        'DLL injection': 'LoadLibrary via remote thread',
        'Atom bombing': 'GlobalAddAtom + APC injection',
        'Process doppelganging': 'Transacted file + process creation',
    }

    def __init__(self):
        self.processes = []
        self.alerts = []

    def add_process(self, pid, ppid, name, parent_name, command_line, user, timestamp):
        self.processes.append({
            'pid': pid, 'ppid': ppid, 'name': name.lower(),
            'parent': parent_name.lower(), 'cmdline': command_line,
            'user': user, 'time': timestamp,
        })

    def analyze(self):
        alerts = []
        for proc in self.processes:
            for rule_name, rule in self.SUSPICIOUS_PARENT_CHILD.items():
                parents = [p.lower() for p in rule['parents']]
                children = [c.lower() for c in rule['children']]

                if proc['parent'] in parents and proc['name'] in children:
                    alerts.append({
                        'rule': rule_name,
                        'severity': rule['severity'],
                        'mitre': rule['mitre'],
                        'parent': proc['parent'],
                        'child': proc['name'],
                        'cmdline': proc['cmdline'],
                        'user': proc['user'],
                        'pid': proc['pid'],
                    })
        return alerts

    def build_tree(self):
        tree = defaultdict(list)
        for proc in self.processes:
            tree[proc['ppid']].append(proc)
        return tree

    def run(self):
        print('=== Process Tree Analyzer ===')
        analyzer = ProcessTreeAnalyzer()

        print('[*] Suspicious parent-child relationships:')
        for name, rule in analyzer.SUSPICIOUS_PARENT_CHILD.items():
            print(f'    [{rule["severity"]}] {name} ({rule["mitre"]})')
            print(f'        Parents: {", ".join(rule["parents"])}')
            print(f'        Children: {", ".join(rule["children"])}')

        base = int(time.time())
        analyzer.add_process(1000, 500, 'winword.exe', 'explorer.exe', 'winword.exe doc.docm', 'user1', base)
        analyzer.add_process(1001, 1000, 'cmd.exe', 'winword.exe', 'cmd.exe /c powershell -enc JABX...', 'user1', base+1)
        analyzer.add_process(1002, 1001, 'powershell.exe', 'cmd.exe', 'powershell -enc JABX...', 'user1', base+2)
        analyzer.add_process(1003, 800, 'wmiprvse.exe', 'svchost.exe', 'wmiprvse.exe', 'SYSTEM', base+3)
        analyzer.add_process(1004, 1003, 'powershell.exe', 'wmiprvse.exe', 'powershell IEX...', 'SYSTEM', base+4)

        print(f'\n--- Analysis Results ---')
        alerts = analyzer.analyze()
        for a in alerts:
            print(f'    [{a["severity"]}] {a["rule"]}')
            print(f'        {a["parent"]} → {a["child"]} (PID: {a["pid"]})')
            print(f'        Command: {a["cmdline"][:60]}')

        print(f'\n[*] Injection indicators:')
        for name, desc in analyzer.INJECTION_INDICATORS.items():
            print(f'    {name}: {desc}')

        print(f'\n[*] Event sources: Sysmon 1 (ProcessCreate), Sysmon 8 (CreateRemoteThread), Sysmon 10 (ProcessAccess)')

analyzer = ProcessTreeAnalyzer()
analyzer.run()

