import re
import os
import json
from collections import defaultdict

class FirewallLogParser:
    """Firewall log parser with geo-enrichment"""

    LOG_FORMATS = {
        'iptables': r'SRC=(\S+) DST=(\S+) .* PROTO=(\S+) SPT=(\d+) DPT=(\d+)',
        'pf': r'pass|block (in|out) on (\S+): (\S+) > (\S+): .*',
        'windows_firewall': r'(\d{4}-\d{2}-\d{2})\s(\d{2}:\d{2}:\d{2})\s(\S+)\s(\S+)\s(\S+)\s(\S+)\s(\d+)\s(\d+)',
        'fortigate': r'srcip=(\S+) dstip=(\S+) srcport=(\d+) dstport=(\d+) action=(\S+)',
        'palo_alto': r'TRAFFIC,.*,(\S+),(\S+),(\S+),(\S+),.*,(\d+),(\d+),',
    }

    SUSPICIOUS_PORTS = {
        4444: 'Meterpreter default', 5555: 'Common backdoor',
        1337: 'Elite/backdoor', 31337: 'Back Orifice',
        8888: 'Common proxy/backdoor', 9001: 'Tor default',
        6666: 'IRC backdoor', 6667: 'IRC', 12345: 'NetBus',
    }

    # Private IP ranges
    PRIVATE_RANGES = ['10.', '172.16.', '172.17.', '172.18.', '172.19.',
                      '172.20.', '172.21.', '172.22.', '172.23.', '172.24.',
                      '172.25.', '172.26.', '172.27.', '172.28.', '172.29.',
                      '172.30.', '172.31.', '192.168.']

    GEO_DB = {
        '185.220.': {'country': 'Germany', 'org': 'Tor Exit Node'},
        '91.215.': {'country': 'Russia', 'org': 'Bulletproof hosting'},
        '45.77.': {'country': 'Japan', 'org': 'Vultr VPS'},
        '198.51.': {'country': 'US', 'org': 'TEST-NET'},
    }

    def __init__(self):
        self.events = []
        self.stats = defaultdict(int)

    def is_private(self, ip):
        return any(ip.startswith(prefix) for prefix in self.PRIVATE_RANGES)

    def geo_lookup(self, ip):
        for prefix, info in self.GEO_DB.items():
            if ip.startswith(prefix):
                return info
        return {'country': 'Unknown', 'org': 'Unknown'}

    def parse_event(self, src_ip, dst_ip, src_port, dst_port, protocol, action):
        event = {
            'src_ip': src_ip, 'dst_ip': dst_ip,
            'src_port': int(src_port), 'dst_port': int(dst_port),
            'protocol': protocol, 'action': action,
            'src_geo': self.geo_lookup(src_ip) if not self.is_private(src_ip) else {'country': 'Internal', 'org': 'LAN'},
            'alerts': [],
        }

        if int(dst_port) in self.SUSPICIOUS_PORTS:
            event['alerts'].append(f'Suspicious port: {dst_port} ({self.SUSPICIOUS_PORTS[int(dst_port)]})')

        if not self.is_private(dst_ip) and int(dst_port) not in (80, 443, 53):
            event['alerts'].append(f'Outbound to non-standard port: {dst_port}')

        self.events.append(event)
        self.stats[action] += 1
        return event

    def detect_port_scan(self, threshold=20):
        src_dst_ports = defaultdict(set)
        for e in self.events:
            key = (e['src_ip'], e['dst_ip'])
            src_dst_ports[key].add(e['dst_port'])

        scans = []
        for (src, dst), ports in src_dst_ports.items():
            if len(ports) >= threshold:
                scans.append({'scanner': src, 'target': dst, 'ports': len(ports), 'geo': self.geo_lookup(src)})
        return scans

    def run(self):
        print('=== Firewall Log Parser ===')
        parser = FirewallLogParser()

        print('[*] Supported log formats:')
        for fmt in parser.LOG_FORMATS:
            print(f'    {fmt}')

        print(f'\n[*] Suspicious ports:')
        for port, desc in parser.SUSPICIOUS_PORTS.items():
            print(f'    {port}: {desc}')

        # Demo events
        events = [
            ('185.220.101.34', '192.168.1.10', '54321', '443', 'TCP', 'ALLOW'),
            ('91.215.85.142', '192.168.1.10', '12345', '4444', 'TCP', 'DROP'),
            ('192.168.1.50', '45.77.65.211', '55555', '8888', 'TCP', 'ALLOW'),
            ('10.0.0.100', '192.168.1.1', '1025', '22', 'TCP', 'ALLOW'),
        ]

        print(f'\n--- Log Analysis ---')
        for src, dst, sp, dp, proto, action in events:
            event = parser.parse_event(src, dst, sp, dp, proto, action)
            geo = event['src_geo']
            alerts = ' '.join(f'[!]{a}' for a in event['alerts'])
            print(f'    [{action}] {src} ({geo["country"]}) → {dst}:{dp}/{proto} {alerts}')

        print(f'\n--- Statistics ---')
        for action, count in parser.stats.items():
            print(f'    {action}: {count}')

        print(f'\n[*] Detection: correlate with threat intel feeds, GeoIP anomalies')

parser = FirewallLogParser()
parser.run()
